#include <bits/stdc++.h>
using namespace std;
const int N=300005;
struct node 
{
    int l,r,id,num;
} q[N];
long long n,m,id[N],a[N],vis[N],block,ans[N],k,siz;
map<int,int> mmap;
map<int,map<int,int> >map2;
bool cmp(node x,node y)
{
    if(x.id==y.id) return x.r<y.r;
    return x.id<y.id;
}
void del(int num)
{
    map2[mmap[num]].erase(num);
    if(map2[mmap[num]].empty()) map2.erase(mmap[num]);
    map2[--mmap[num]][num]=1;   
}
void add(int num)
{
    map2[mmap[num]].erase(num);
    if(map2[mmap[num]].empty()) map2.erase(mmap[num]);
    map2[++mmap[num]][num]=1;   
}
